sql:
SELECT AVG(attendance) AS average_attendance
FROM games
WHERE favored = 1;

SELECT COUNT(video_id) AS video_count
FROM game_videos
WHERE game_id = 1;

SELECT game_id
FROM games
ORDER BY date DESC, game_id DESC;

SELECT date, opponent
FROM games
ORDER BY date DESC;

SELECT game_id, total
FROM games
WHERE favored = 1 AND total > 200;

SELECT game_id
FROM games
ORDER BY date DESC;

SELECT COUNT(comment_id) AS comment_count
FROM game_comments
WHERE game_id = 0;

SELECT COUNT(*) AS total_games
FROM games
WHERE game_type = 'Regular Season' AND date >= '2023-01-01' AND date <= '2023-12-31';
